#include "interface.h"
#include <algorithm>

uint64_t join_sum(
    const std::vector<uint32_t>& dim_keys,
    const std::vector<uint32_t>& dim_values,
    const std::vector<uint32_t>& probe_keys,
    const std::vector<uint32_t>& probe_weights,
    int iters) {
  uint64_t sum = 0;
  bool is_consecutive = true;
  for (size_t i = 1; i < dim_keys.size(); ++i) {
    if (dim_keys[i] != dim_keys[i-1] + 1) {
      is_consecutive = false;
      break;
    }
  }

  for (int iter = 0; iter < iters; ++iter) {
    sum = 0;
    if (is_consecutive) {
      uint32_t base = dim_keys[0];
      for (std::size_t i = 0; i < probe_keys.size(); ++i) {
        uint32_t key = probe_keys[i];
        if (key >= base && key < base + dim_keys.size()) {
          sum += static_cast<uint64_t>(dim_values[key - base]) * static_cast<uint64_t>(probe_weights[i]);
        }
      }
    } else {
      for (std::size_t i = 0; i < probe_keys.size(); ++i) {
        const auto it = std::lower_bound(dim_keys.begin(), dim_keys.end(), probe_keys[i]);
        const std::size_t idx = static_cast<std::size_t>(it - dim_keys.begin());
        sum += static_cast<uint64_t>(dim_values[idx]) * static_cast<uint64_t>(probe_weights[i]);
      }
    }
  }
  return sum;
}
